"use client";

import { useEffect } from "react";
import { useSession } from "next-auth/react";
import {
  Dialog,
  DialogContent,
  DialogDescription,
  DialogHeader,
  DialogTitle,
} from "@/components/ui/dialog";
import { Select, SelectContent, SelectItem, SelectTrigger } from "@/components/ui/select";
import { Tooltip, TooltipContent, TooltipTrigger } from "@/components/ui/tooltip";
import {
  useJobStore,
  initializeJobFromSession,
  selectJobs,
  selectIsLoading,
  selectError,
} from "@/store/jobStore";
import { truncateText, truncateJobName, MAX_EXTERNAL_ID_LENGTH } from "@/lib/utils/jobFormatting";
import { Briefcase } from "lucide-react";

export default function JobSelectionModal() {
  const { data: session } = useSession();
  const showJobModal = useJobStore((state) => state.showJobModal);
  const setSelectedJob = useJobStore((state) => state.setSelectedJob);
  const closeJobModal = useJobStore((state) => state.closeJobModal);
  const selectedJob = useJobStore((state) => state.selectedJob);
  const jobs = useJobStore(selectJobs);
  const isLoading = useJobStore(selectIsLoading);
  const error = useJobStore(selectError);

  // Initialize from sessionStorage on mount, then fetch jobs
  useEffect(() => {
    initializeJobFromSession();
    const userEmail = session?.user?.email ?? undefined;
    useJobStore.getState().loadJobs(userEmail);
  // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [session?.user?.email]);

  // Only open modal after jobs have loaded and there are jobs to pick from
  useEffect(() => {
    if (!isLoading && !error && jobs.length > 0) {
      const storedJob = sessionStorage.getItem("selectedJob");
      if (!storedJob) {
        useJobStore.getState().openJobModal();
      }
    }
  }, [isLoading, error, jobs.length]);

  const handleJobSelect = (jobId: string) => {
    setSelectedJob(jobId);
    closeJobModal();
  };

  // Prevent closing the modal without selecting a job (unless no jobs are available or there's an error)
  const canClose = !!selectedJob || !!error || jobs.length === 0;
  const handleOpenChange = (open: boolean) => {
    if (!open && !canClose) {
      return;
    }
    if (!open) {
      closeJobModal();
    }
  };

  return (
    <Dialog open={showJobModal} onOpenChange={handleOpenChange}>
      <DialogContent
        className="sm:max-w-md"
        hideCloseButton={!canClose}
        onInteractOutside={(e) => {
          if (!canClose) {
            e.preventDefault();
          }
        }}
        onEscapeKeyDown={(e) => {
          if (!canClose) {
            e.preventDefault();
          }
        }}
      >
        <DialogHeader>
          <DialogTitle className="flex items-center gap-2">
            <Briefcase className="size-5" />
            Select a Job
          </DialogTitle>
          <DialogDescription>
            Please select a job to continue. This helps us organize your work across all tools.
          </DialogDescription>
        </DialogHeader>
        <div className="py-4">
          <Select onValueChange={handleJobSelect} value={selectedJob || undefined}>
            <SelectTrigger className="w-full h-12 bg-muted">
              {selectedJob ? (
                {(() => {
                const selectedJobData = jobs.find((j) => j.id === selectedJob);
                const externalId = selectedJobData?.external_id?.toUpperCase() || "";
                const jobName = selectedJobData?.name || "";
                return (
                  <div className="flex items-center gap-2">
                    <span className="text-xs text-muted-foreground bg-background px-2 py-0.5 rounded border font-medium w-[70px] text-center truncate" title={externalId}>
                      {truncateText(externalId, MAX_EXTERNAL_ID_LENGTH)}
                    </span>
                    <Tooltip>
                      <TooltipTrigger asChild>
                        <span className="truncate max-w-[200px]">
                          {truncateJobName(jobName)}
                        </span>
                      </TooltipTrigger>
                      <TooltipContent side="bottom">
                        {jobName}
                      </TooltipContent>
                    </Tooltip>
                  </div>
                );
              })()}
              ) : (
                <span className="text-muted-foreground">Choose a job...</span>
              )}
            </SelectTrigger>
            <SelectContent>
              {jobs.map((job) => (
                <SelectItem key={job.id} value={job.id}>
                  <div className="flex items-center gap-2">
                    <span className="text-xs text-muted-foreground bg-muted px-2 py-0.5 rounded font-medium w-[70px] text-center truncate" title={job.external_id.toUpperCase()}>
                      {truncateText(job.external_id.toUpperCase(), MAX_EXTERNAL_ID_LENGTH)}
                    </span>
                    <span>{truncateJobName(job.name)}</span>
                  </div>
                </SelectItem>
              ))}
            </SelectContent>
          </Select>
        </div>
      </DialogContent>
    </Dialog>
  );
}

